OFFICIAL_K562_BLUEPRINT_IDS = {
    item["id"] for item in MODEL_BLUEPRINTS if item.get("official_k562")
}


def blueprints(status: str | None = None) -> list[dict[str, Any]]:
    if status is None:
        return list(MODEL_BLUEPRINTS)
    return [item for item in MODEL_BLUEPRINTS if item["status"] == status]


def implemented_blueprint_ids() -> list[str]:
    return [item["id"] for item in blueprints("implemented")]


def selectable_blueprint_ids(include_planned: bool = False, official_k562_only: bool = False) -> list[str]:
    items = MODEL_BLUEPRINTS
    if official_k562_only:
        items = [item for item in items if item.get("official_k562")]
    if include_planned:
        return [item["id"] for item in items if item["status"] in {"implemented", "planned", "planned_for_codex"}]
    return [item["id"] for item in items if item["status"] == "implemented"]


def blueprint_by_id(blueprint_id: str) -> dict[str, Any]:
    for item in MODEL_BLUEPRINTS:
        if item["id"] == blueprint_id:
            return item
    raise KeyError(f"unknown model blueprint {blueprint_id!r}")
